// And groups predicates with the AND operator between them.
func And(predicates ...predicate.ProductionOrder) predicate.ProductionOrder {
	return predicate.ProductionOrder(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.ProductionOrder) predicate.ProductionOrder {
	return predicate.ProductionOrder(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.ProductionOrder) predicate.ProductionOrder {
	return predicate.ProductionOrder(sql.NotPredicates(p))
}
